class Solution {
public:
    int numMusicPlaylists(int n, int goal, int k) {
        const int MOD = 1e9 + 7;
        long long dp[goal + 1][n + 1] = {};
        for (int i = 1; i <= goal; i++) {
            for (int j = 1; j <= n; j++) {
                if (i == 1) {
                    dp[i][j] = j;
                } else if (j == 1) {
                    dp[i][j] = (dp[i - 1][n] + (k + 1 == i ? 1 : 0)) % MOD;
                } else {
                    dp[i][j] = (dp[i - 1][j - 1] * (n - j + 1) + dp[i - 1][j] * (k + 1 == i ? 1 : 0)) % MOD;
                }
            }
        }
        return dp[goal][n];
    }
};
